#include <stdio.h>
#include <string.h>

int in_row(char ch) {
    if (ch == 'f') return 1;
    if (ch == 'a') return 4;
    if (ch == 'b') return 5;
    if (ch == 'c') return 6;
    if (ch == 'd') return 3;
    if (ch == 'e') return 2;
    return 0;
}

int main() {
    char li[10];
    scanf("%s", li);
    int n = li[0] - '0';
    char s = li[strlen(li) - 1];
    int time = 0;
    int tmp = (n - 1) / 4;
    time += tmp * 3 + tmp * 13;
    tmp = (n - 1) % 4;
    if (tmp == 1 || tmp == 3) {
        time += 7;
    }
    time += in_row(s);
    printf("%d", time);
    return 0;
}
